class ProductionVerboseTree(private val prefix: String) : Timber.DebugTree() {
    override fun createStackElementTag(element: StackTraceElement): String {
        val base = "${element.fileName}:${element.lineNumber}#${element.methodName}"
        val tag = "$prefix:$base"
        return if (tag.length <= 23) tag else tag.takeLast(23)
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val safeTag = tag ?: prefix
        if (message.length < 4000) {
            Log.println(priority, safeTag, message)
        } else {
            var i = 0
            val length = message.length
            while (i < length) {
                val end = (i + 4000).coerceAtMost(length)
                Log.println(priority, safeTag, message.substring(i, end))
                i = end
            }
        }
        if (t != null) {
            Log.println(priority, safeTag, Log.getStackTraceString(t))
        }
    }
}

object AuthLogger {
    fun attempt(
        usernameOrId: String?,
        method: String,
        success: Boolean,
        reason: String? = null,
        userId: String? = null,
        extras: Map<String, Any?> = emptyMap()
    ) {
        if (!AppLogger.enabled) return
        val safeUser = usernameOrId ?: "null"
        val safeUserId = userId ?: "null"
        val safeReason = reason ?: "null"
        val extraStr = if (extras.isEmpty()) "" else " extras=${extras.entries.joinToString(prefix = "{", postfix = "}") { "${it.key}=${it.value}" }}"
        if (success) {
            AppLogger.i(
                "AUTH success method=%s usernameOrId=%s userId=%s reason=%s%s",
                method, safeUser, safeUserId, safeReason, extraStr
            )
        } else {
            AppLogger.w(
                "AUTH failure method=%s usernameOrId=%s userId=%s reason=%s%s",
                method, safeUser, safeUserId, safeReason, extraStr
            )
        }
    }
}

object DbLogger {
    fun query(
        sql: String,
        args: List<Any?> = emptyList(),
        durationMs: Long? = null,
        rows: Int? = null,
        dbName: String? = null
    ) {
        if (!AppLogger.enabled) return
        val argStr = args.joinToString(prefix = "[", postfix = "]") { it.safeToString(2000) }
        val dur = durationMs?.toString() ?: "null"
        val r = rows?.toString() ?: "null"
        val name = dbName ?: "default"
        AppLogger.d("DB query db=%s durationMs=%s rows=%s sql=%s args=%s", name, dur, r, sql, argStr)
    }

    fun exec(
        sql: String,
        args: List<Any?> = emptyList(),
        durationMs: Long? = null,
        affected: Int? = null,
        dbName: String? = null
    ) {
        if (!AppLogger.enabled) return
        val argStr = args.joinToString(prefix = "[", postfix = "]") { it.safeToString(2000) }
        val dur = durationMs?.toString() ?: "null"
        val a = affected?.toString() ?: "null"
        val name = dbName ?: "default"
        AppLogger.d("DB exec db=%s durationMs=%s affected=%s sql=%s args=%s", name, dur, a, sql, argStr)
    }

    private fun Any?.safeToString(maxLen: Int): String {
        val s = when (this) {
            null -> "null"
            is ByteArray -> "byteArray(size=$size)"
            else -> toString()
        }
        return if (s.length <= maxLen) s else s.take(maxLen) + "…(truncated)"
    }
}

class ApiLoggingInterceptor(
    private val includeHeaders: Boolean = true,
    private val includeBody: Boolean = true,
    private val maxBodyBytes: Long = 1024L * 1024L,
    private val redactHeaders: Set<String> = setOf("Authorization", "Cookie", "Set-Cookie", "X-Api-Key"),
    private val tag: String = "API"
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val requestId = UUID.randomUUID().toString()
        val request = chain.request()
        val startNs = System.nanoTime()

        logRequest(requestId, request)

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            logResponse(requestId, response, tookMs)
            response
        } catch (t: Throwable) {
            AppLogger.e(t, "%s exception requestId=%s method=%s url=%s", tag, requestId, request.method, request.url)
            throw t
        }
    }

    private fun logRequest(requestId: String, request: Request) {
        if (!AppLogger.enabled) return
        val url = request.url.toString()
        val method = request.method
        val headersStr = if (includeHeaders) headersToString(request.headers) else "(headers omitted)"
        val bodyStr = if (includeBody) requestBodyToString(request) else "(body omitted)"
        AppLogger.v("%s request requestId=%s method=%s url=%s\nheaders=%s\nbody=%s", tag, requestId, method, url, headersStr, bodyStr)
    }

    private fun logResponse(requestId: String, response: Response, tookMs: Long) {
        if (!AppLogger.enabled) return
        val req = response.request
        val url = req.url.toString()
        val code = response.code
        val message = response.message
        val headersStr = if (includeHeaders) headersToString(response.headers) else "(headers omitted)"

        if (!includeBody) {
            AppLogger.v(
                "%s response requestId=%s method=%s url=%s code=%s message=%s tookMs=%s\nheaders=%s\nbody=%s",
                tag, requestId, req.method, url, code, message, tookMs, headersStr, "(body omitted)"
            )
            return
        }

        val responseBody = response.body
        if (responseBody == null) {
            AppLogger.v(
                "%s response requestId=%s method=%s url=%s code=%s message=%s tookMs=%s\nheaders=%s\nbody=%s",
                tag, requestId, req.method, url, code, message, tookMs, headersStr, "null"
            )
            return
        }

        val contentType = responseBody.contentType()
        val source = responseBody.source()
        source.request(maxBodyBytes.coerceAtMost(Long.MAX_VALUE))
        val buffer = source.buffer

        val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
        val isPlain = buffer.isProbablyUtf8()
        val bodyString = if (isPlain) {
            val byteCount = buffer.size.coerceAtMost(maxBodyBytes)
            val clone = buffer.clone()
            val text = clone.readString(byteCount, charset)
            if (buffer.size > maxBodyBytes) text + "…(truncated)" else text
        } else {
            "(${buffer.size} bytes, binary omitted)"
        }

        AppLogger.v(
            "%s response requestId=%s method=%s url=%s code=%s message=%s tookMs=%s\nheaders=%s\nbody=%s",
            tag, requestId, req.method, url, code, message, tookMs, headersStr, bodyString
        )

        val bytes = buffer.clone().readByteArray()
        val newBody = ResponseBody.create(contentType, bytes)
        response.newBuilder().body(newBody).build()
    }

    private fun headersToString(headers: Headers): String {
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = if (redactHeaders.any { it.equals(name, ignoreCase = true) }) "***REDACTED***" else headers.value(i)
            sb.append(name).append(": ").append(value)
            if (i < headers.size - 1) sb.append("\n")
        }
        return sb.toString()
    }

    private fun requestBodyToString(request: Request): String {
        val body = request.body ?: return "null"
        return try {
            val buffer = Buffer()
            val contentType = body.contentType()
            body.writeTo(buffer)

            val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val isPlain = buffer.isProbablyUtf8()
            if (!isPlain) return "(${buffer.size} bytes, binary omitted)"

            val byteCount = buffer.size.coerceAtMost(maxBodyBytes)
            val text = buffer.clone().readString(byteCount, charset)
            if (buffer.size > maxBodyBytes) text + "…(truncated)" else text
        } catch (t: Throwable) {
            AppLogger.e(t, "%s requestBodyToString failed", tag)
            "(failed to read body: ${t.javaClass.simpleName})"
        }
    }

    private fun Buffer.isProbablyUtf8(): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = size.coerceAtMost(64)
            copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) return false
            }
            true
        } catch (_: EOFException) {
            false
        } catch (_: Throwable) {
            false
        }
    }
}

object ExceptionLogging {
    fun installGlobalHandlers() {
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            try {
                AppLogger.logException(
                    throwable,
                    context = "UncaughtException",
                    extras = mapOf("thread" to thread.name, "id" to thread.id)
                )
            } catch (_: Throwable) {
            } finally {
                defaultHandler?.uncaughtException(thread, throwable)
            }
        }
    }

    inline fun <T> runCatchingLogged(context: String, extras: Map<String, Any?> = emptyMap(), block: () -> T): T {
        try {
            return block()
        } catch (t: Throwable) {
            AppLogger.logException(t, context, extras)
            throw t
        }
    }
}

object LoggingOkHttp {
    fun createClient(
        base: OkHttpClient? = null,
        includeHeaders: Boolean = true,
        includeBody: Boolean = true,
        maxBodyBytes: Long = 1024L * 1024L
    ): OkHttpClient {
        val builder = (base?.newBuilder() ?: OkHttpClient.Builder())
        builder.addInterceptor(ApiLoggingInterceptor(includeHeaders, includeBody, maxBodyBytes))
        return builder.build()
    }
}

